from dataclasses import dataclass, field
from datetime import date, timedelta
from typing import Literal

DeprecationPhase = Literal["audit", "evaluate", "canary", "complete"]

@dataclass
class ModelMigrationPlan:
    deprecated_model: str
    successor_model: str
    sunset_date: date
    impacted_prompt_ids: list[str]
    impacted_services: list[str]

    @property
    def phase_dates(self) -> dict[DeprecationPhase, date]:
        return {
            "audit":    self.sunset_date - timedelta(days=90),
            "evaluate": self.sunset_date - timedelta(days=60),
            "canary":   self.sunset_date - timedelta(days=30),
            "complete": self.sunset_date - timedelta(days=7),
        }

    @property
    def current_phase(self) -> DeprecationPhase:
        today = date.today()
        for phase in ["complete", "canary", "evaluate", "audit"]:
            if today >= self.phase_dates[phase]:  # type: ignore[index]
                return phase  # type: ignore[return-value]
        return "audit"

    def is_overdue(self) -> bool:
        phase = self.current_phase
        return date.today() > self.phase_dates[phase]  # type: ignore[index]

def audit_model_references(model_id: str, repo_root: str) -> list[str]:
    """Return all file paths that reference the given model ID."""
    import subprocess, pathlib
    result = subprocess.run(
        ["git", "grep", "-rl", "--", model_id],
        capture_output=True, text=True, cwd=repo_root,
    )
    return [line.strip() for line in result.stdout.splitlines() if line.strip()]

from dataclasses import dataclass
from datetime import date
from typing import Literal

MigrationOutcome = Literal["on_time", "late", "emergency_extension", "not_completed"]

@dataclass
class MigrationRecord:
    deprecated_asset: str       # model ID or prompt version
    sunset_date: date
    caller_service: str
    completed_date: date | None
    outcome: MigrationOutcome

    @classmethod
    def compute_outcome(
        cls,
        sunset_date: date,
        completed_date: date | None,
        emergency_extension: bool,
    ) -> MigrationOutcome:
        if completed_date is None:
            return "not_completed"
        if emergency_extension:
            return "emergency_extension"
        if completed_date <= sunset_date:
            return "on_time"
        return "late"

def compute_sunset_metrics(records: list[MigrationRecord]) -> dict:
    total = len(records)
    if total == 0:
        return {}
    on_time = sum(1 for r in records if r.outcome == "on_time")
    return {
        "total_migrations": total,
        "on_time_rate": on_time / total,
        "late_rate": sum(1 for r in records if r.outcome == "late") / total,
        "not_completed_rate": sum(1 for r in records if r.outcome == "not_completed") / total,
    }
